typedef float fp;

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / (fp)255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        fp val = d_I[ei];
        d_sums[ei] = val;
        d_sums2[ei] = val * val;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int blocks_work_size)
{
    (void)d_Ne;
    (void)blocks_work_size;

    long bx = (long)get_group_id(0);
    long tx = (long)get_local_id(0);
    long lsize = (long)get_local_size(0);

    if (tx == 0) {
        long start = bx * lsize;
        long count = d_no - start;
        if (count > lsize) {
            count = lsize;
        }

        if (count > 0) {
            fp sum = (fp)0.0f;
            fp sum2 = (fp)0.0f;

            for (long i = 0; i < count; i++) {
                long idx = (start + i) * (long)d_mul;
                fp v1 = d_sums[idx];
                fp v2 = d_sums2[idx];
                sum += v1;
                sum2 += v2;
            }

            long out_idx = bx * (long)d_mul * lsize;
            d_sums[out_idx] = sum;
            d_sums2[out_idx] = sum2;
        }
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I)
{
    (void)lambda;
    (void)Nr;

    long ei = (long)get_global_id(0);

    if (ei < Ne) {
        int row = (int)(ei / (long)Nc);
        int col = (int)(ei - (long)row * (long)Nc);

        fp Jc = d_I[ei];

        fp dN = d_I[(long)iN[row] * (long)Nc + (long)col] - Jc;
        fp dS = d_I[(long)iS[row] * (long)Nc + (long)col] - Jc;
        fp dW = d_I[(long)row * (long)Nc + (long)jW[col]] - Jc;
        fp dE = d_I[(long)row * (long)Nc + (long)jE[col]] - Jc;

        d_dN[ei] = dN;
        d_dS[ei] = dS;
        d_dW[ei] = dW;
        d_dE[ei] = dE;

        fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        fp L = (dN + dS + dW + dE) / Jc;

        fp num = ((fp)0.5f * G2) - ((fp)1.0f / (fp)16.0f) * (L * L);
        fp den = (fp)1.0f + ((fp)0.25f * L);
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * ((fp)1.0f + q0sqr));
        fp c = (fp)1.0f / ((fp)1.0f + den);

        if (c < (fp)0.0f) {
            c = (fp)0.0f;
        } else if (c > (fp)1.0f) {
            c = (fp)1.0f;
        }

        d_c[ei] = c;
    }
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I)
{
    (void)Nr;
    (void)iN;
    (void)jW;

    long ei = (long)get_global_id(0);

    if (ei < Ne) {
        int row = (int)(ei / (long)Nc);
        int col = (int)(ei - (long)row * (long)Nc);

        fp cN = d_c[ei];
        fp cS = d_c[(long)iS[row] * (long)Nc + (long)col];
        fp cW = d_c[ei];
        fp cE = d_c[(long)row * (long)Nc + (long)jE[col]];

        fp D = cN * d_dN[ei] +
               cS * d_dS[ei] +
               cW * d_dW[ei] +
               cE * d_dE[ei];

        d_I[ei] = d_I[ei] + ((fp)0.25f * lambda * D);
    }
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}
